5	const CACHE_KEY = 'destinations:all';
6	const CACHE_TTL = parseInt(process.env.CACHE_TTL_DESTINATIONS || '86400');
7	
8	export async function GET() {
9	  try {
10	    const cached = await cacheGet(CACHE_KEY);
11	    if (cached) {
12	      return NextResponse.json(cached, { headers: { 'X-Cache': 'HIT' } });
13	    }
14	
15	    const result = await pgPool.query(`
16	      SELECT
17	        d.id,
18	        d.slug,
19	        d.name,
20	        d.summary                                                  AS "shortDesc",
21	        d.difficulty_level                                         AS difficulty,
22	        json_build_object('url', d.thumbnail_url, 'alt_text', d.name) AS image
23	      FROM destinations d
24	      WHERE d.deleted_at IS NULL
25	        AND d.published = true
26	      ORDER BY d.name;
27	    `);
28	
29	    const destinations = result.rows;
30	
31	    await cacheSet(CACHE_KEY, destinations, CACHE_TTL);
32	
33	    return NextResponse.json(destinations, {
34	      headers: { 'X-Cache': 'MISS' },
35	    });
36	  } catch (error) {
37	    console.error('Destinations API error:', error);
38	    return NextResponse.json(
39	      { error: 'Failed to fetch destinations' },
40	      { status: 500 }
41	    );
42	  }
43	}
