18	      SELECT
19	        p.id,
20	        p.slug,
21	        p.name,
22	        p.description                             AS "shortDesc",
23	        COALESCE(p.aggregate_rating_value, 4.9)  AS rating,
24	        (
25	          SELECT COALESCE(MIN(pp.price), 0)
26	          FROM package_prices pp
27	          WHERE pp.package_id = p.id AND pp.deleted_at IS NULL
28	        ) AS "priceFrom",
29	        (
30	          SELECT COALESCE(json_agg(
31	            json_build_object('url', pi.url, 'alt_text', pi.alt_text)
32	            ORDER BY pi.sort_order
33	          ), '[]'::json)
34	          FROM package_images pi
35	          WHERE pi.package_id = p.id AND pi.deleted_at IS NULL
36	        ) AS images
37	      FROM packages p
38	      WHERE p.deleted_at IS NULL
39	        AND p.is_publish = true
40	      ORDER BY p.created_at DESC;
41	    `);
42	
43	    const tours = result.rows;
44	
45	    await cacheSet(CACHE_KEY, tours, CACHE_TTL);
46	
47	    return NextResponse.json(tours, {
48	      headers: { 'X-Cache': 'MISS' },
49	    });
50	  } catch (error) {
51	    console.error('Tours API error:', error);
52	    return NextResponse.json(
53	      { error: 'Failed to fetch tours' },
54	      { status: 500 }
55	    );
56	  }
57	}
