1	import { createClient, type RedisClientType } from 'redis';
2	
3	let redisClient: RedisClientType | null = null;
4	
5	export async function getRedisClient(): Promise<RedisClientType> {
6	  if (redisClient && redisClient.isOpen) {
7	    return redisClient;
8	  }
9	
10	  redisClient = createClient({
11	    url: process.env.REDIS_URL || 'redis://localhost:6379',
12	  });
13	
14	  redisClient.on('error', (err) => {
15	    console.error('Redis Client Error', err);
16	  });
17	
18	  redisClient.on('connect', () => {
19	    console.log('Redis client connected');
20	  });
21	
22	  try {
23	    await redisClient.connect();
24	  } catch (err) {
25	    console.error('Failed to connect to Redis:', err);
26	    // Don't throw—allow app to run without Redis in development
27	  }
28	
29	  return redisClient;
30	}
