32	export async function cacheGet<T>(key: string): Promise<T | null> {
33	  try {
34	    const client = await getRedisClient();
35	    if (!client.isOpen) {
36	      return null;
37	    }
38	    const value = await client.get(key);
39	    if (!value) {
40	      return null;
41	    }
42	    return JSON.parse(value);
43	  } catch (error) {
44	    console.error(`Cache get error for key ${key}:`, error);
45	    return null; // Graceful fallback on cache error
46	  }
47	}
48	
49	export async function cacheSet<T>(
50	  key: string,
51	  value: T,
52	  ttlSeconds: number = 3600
53	): Promise<void> {
54	  try {
55	    const client = await getRedisClient();
56	    if (!client.isOpen) {
57	      return;
58	    }
59	    await client.setEx(key, ttlSeconds, JSON.stringify(value));
60	  } catch (error) {
61	    console.error(`Cache set error for key ${key}:`, error);
62	    // Don't throw—cache failure shouldn't break the app
63	  }
64	}
65	
66	export async function cacheDelete(key: string): Promise<void> {
67	  try {
68	    const client = await getRedisClient();
69	    if (!client.isOpen) {
70	      return;
71	    }
72	    await client.del(key);
73	  } catch (error) {
74	    console.error(`Cache delete error for key ${key}:`, error);
75	  }
76	}
77	
78	export async function cacheInvalidatePattern(pattern: string): Promise<void> {
79	  try {
80	    const client = await getRedisClient();
81	    if (!client.isOpen) {
82	      return;
83	    }
84	    const keys = await client.keys(pattern);
85	    if (keys.length > 0) {
86	      await client.del(keys);
87	    }
88	  } catch (error) {
89	    console.error(`Cache invalidate pattern error for ${pattern}:`, error);
90	  }
91	}
92	
93	export async function closeRedisClient(): Promise<void> {
94	  if (redisClient && redisClient.isOpen) {
95	    await redisClient.quit();
96	  }
97	}
