1	import { NextResponse } from 'next/server';
2	import { pgPool } from '@/lib/db';
3	import { cacheGet, cacheSet } from '@/lib/cache';
4	
5	const CACHE_TTL = parseInt(process.env.CACHE_TTL_REVIEWS || '43200');
6	
7	export async function GET(request: Request) {
8	  try {
9	    const url = new URL(request.url);
10	    const limit = parseInt(url.searchParams.get('limit') || '8');
11	    const platform = url.searchParams.get('platform'); // optional filter
12	
13	    let cacheKey = `reviews:database:${limit}`;
14	    if (platform) {
15	      cacheKey += `:${platform}`;
16	    }
17	
18	    // Try cache first
19	    const cached = await cacheGet(cacheKey);
20	    if (cached) {
21	      return NextResponse.json(cached, { headers: { 'X-Cache': 'HIT' } });
22	    }
23	
24	    // Query database reviews (star >= 4)
25	    let query = `
26	      SELECT
27	        id,
28	        customer_name as name,
29	        review as text,
30	        star as rating,
31	        platform as source,
32	        date,
33	        profile_photo as photo
34	      FROM reviews
35	      WHERE review IS NOT NULL
36	        AND LENGTH(review) > 30
37	        AND star >= 4
38	    `;
39	
40	    const params: any[] = [];
41	
42	    if (platform) {
43	      query += ` AND LOWER(platform) = LOWER($1)`;
44	      params.push(platform);
45	      query += ` ORDER BY date DESC LIMIT $${params.length + 1}`;
46	      params.push(limit);
47	    } else {
48	      query += ` ORDER BY date DESC LIMIT $1`;
49	      params.push(limit);
50	    }
51	
52	    const result = await pgPool.query(query, params);
53	    const reviews = result.rows;
54	
55	    // Cache with configured TTL
56	    await cacheSet(cacheKey, reviews, CACHE_TTL);
57	
58	    return NextResponse.json(reviews, {
59	      headers: { 'X-Cache': 'MISS' },
60	    });
61	  } catch (error) {
62	    console.error('Reviews API error:', error);
63	    return NextResponse.json(
64	      { error: 'Failed to fetch reviews' },
65	      { status: 500 }
66	    );
67	  }
68	}
